import{_ as o,o as t,c as i,a3 as a}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse('{"title":"55. Daylight Saving","description":"","frontmatter":{"title":"55. Daylight Saving","eba":"Nurses and Midwives 2024-2028","topics":["hours","overtime","shift-work","breaks"]},"headers":[],"relativePath":"ebas/nurses-midwives/hours-of-work/55-daylight-saving.md","filePath":"ebas/nurses-midwives/hours-of-work/55-daylight-saving.md"}'),r={name:"ebas/nurses-midwives/hours-of-work/55-daylight-saving.md"};function s(n,e,h,l,d,u){return t(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="_55-daylight-saving" tabindex="-1">55. Daylight Saving <a class="header-anchor" href="#_55-daylight-saving" aria-label="Permalink to &quot;55. Daylight Saving&quot;">​</a></h1><p>See also <a href="/eba/ebas/nurses-midwives/hours-of-work/49-overtime.html">clauses 49</a> (Overtime) and 0 (Accrued Days Off).</p><p><strong>55.1</strong> Despite the overtime provisions of this Agreement, if an Employee works on a shift during which time changes because of the introduction of, or cessation to, daylight saving, that Employee will be paid for the actual hours worked at the ordinary time rate of pay.</p><p>Example: An Employee is rostered to work a ten hour night shift from 9pm through to 7:30am (including a 30 minute meal break). During the course of this shift, the clock is wound forward one hour due to the commencement of daylight saving. The Employee therefore works nine hours. The Employee is paid nine hours at their ordinary time rate of pay (including any shift penalties or allowances ordinarily payable in respect of this shift).</p><p>Example: An Employee is rostered in a ten hour night shift from 9pm through to 7.30am (including a 30 minute meal break). During the course of this shift, the clock is wound back one hour due to the cessation of daylight saving. The Employee therefore works 11 hours. The Employee is paid 11 hours at their ordinary time rate of pay (including any shift penalties or allowances ordinarily payable in respect of this shift). No overtime is paid for the additional hour worked.</p><p><strong>55.2</strong> For the purpose of calculating accrued days off, Employees who work on a shift during which time changes because of the introduction of, or cessation to, daylight saving, will be taken to have worked the standard hours for a night shift in accordance with the roster.</p>',6)])])}const p=o(r,[["render",s]]);export{f as __pageData,p as default};
